-- db/seed-aldiyaa-company-defaults.sql
--
-- Mirrors artifacts/api-server/src/lib/companyBootstrap.ts so the
-- Al-Diyaa wal-Bayan company gets the same defaults that the API
-- assigns to a newly-created company:
--   • chart of accounts (~150 rows)
--   • role permissions (~14 roles)
--   • HR leave types (10)
--   • shifts (3, linked to Al-Door branch)
--   • salary components (6)
--   • system_settings (config, numbering, violation types,
--     approval chains, penalty ladder)
--
-- The base company + branches + owner come from
-- db/seed-aldiyaa-albayan.sql, so this file is meant to run AFTER
-- that one (bootstrap.sh chains them in order).
--
-- Idempotent: every INSERT uses ON CONFLICT DO NOTHING.

BEGIN;

DO $$
DECLARE
  v_company_id integer;
  v_branch_id  integer;
BEGIN
  SELECT id INTO v_company_id
    FROM companies
   WHERE name = 'مؤسسة الضياء والبيان للمقاولات'
   LIMIT 1;

  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'Al-Diyaa company missing — run seed-aldiyaa-albayan.sql first';
  END IF;

  SELECT id INTO v_branch_id
    FROM branches
   WHERE "companyId" = v_company_id
     AND name = 'مؤسسة الدور الحديثة للتطوير العقاري'
   LIMIT 1;

  -- =====================================================================
  -- HR leave types
  -- =====================================================================


  -- =====================================================================
  -- Shifts (linked to Al-Door branch)
  -- =====================================================================

  -- =====================================================================
  -- Salary components
  -- =====================================================================

  -- =====================================================================
  -- Chart of accounts (~150 rows; parent IDs resolved via lookup)
  -- =====================================================================

  -- =====================================================================
  -- Role permissions
  -- =====================================================================

  -- =====================================================================
  -- Violation types (as system_settings JSON entries)
  -- =====================================================================

  -- =====================================================================
  -- Approval chains
  -- =====================================================================

  -- =====================================================================
  -- Numbering prefixes
  -- =====================================================================

  -- =====================================================================
  -- Penalty ladder
  -- =====================================================================

  -- =====================================================================
  -- General system_settings (~200 keys)
  -- =====================================================================

  RAISE NOTICE 'Al-Diyaa defaults seeded: companyId=%, branchId=%', v_company_id, v_branch_id;
END $$;

COMMIT;

-- Sanity check
SELECT 'chart_of_accounts' AS table_name, count(*) FROM chart_of_accounts WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات')
UNION ALL SELECT 'role_permissions', count(*) FROM role_permissions WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات')
UNION ALL SELECT 'hr_leave_types', count(*) FROM hr_leave_types WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات')
UNION ALL SELECT 'shifts', count(*) FROM shifts WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات')
UNION ALL SELECT 'salary_components', count(*) FROM salary_components WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات')
UNION ALL SELECT 'system_settings', count(*) FROM system_settings WHERE "companyId" = (SELECT id FROM companies WHERE name='مؤسسة الضياء والبيان للمقاولات');
